 -P
 use-apache-snapshots
diff --git a/server/base/src/main/java/org/apache/accumulo/server/metadata/ConditionalTabletsMutatorImpl.java b/server/base/src/main/java/org/apache/accumulo/server/metadata/ConditionalTabletsMutatorImpl.java
index 777364e0c4..8f4d59ec36 100644
--- a/server/base/src/main/java/org/apache/accumulo/server/metadata/ConditionalTabletsMutatorImpl.java
+++ b/server/base/src/main/java/org/apache/accumulo/server/metadata/ConditionalTabletsMutatorImpl.java
@@ -66,10 +66,25 @@ public class ConditionalTabletsMutatorImpl implements Ample.ConditionalTabletsMu

   private boolean active = true;

+  @Override
+  public void close() {
+    active = false;
+    extents.clear();
+    mutations.clear();
+    rejectedHandlers.clear();
+    operationDescriptions.clear();
+    originalRejectedHandlers.clear();
+    originalOperationDescriptions.clear();
+    dataLevel = null;
+  }
+
   final Map<KeyExtent,Ample.RejectionHandler> rejectedHandlers = new HashMap<>();
   private final Map<KeyExtent,Supplier<String>> operationDescriptions = new HashMap<>();
   private final Function<DataLevel,String> tableMapper;

+  private final Map<KeyExtent,Ample.RejectionHandler> originalRejectedHandlers = new HashMap<>();
+  private final Map<KeyExtent,Supplier<String>> originalOperationDescriptions = new HashMap<>();
+
   public ConditionalTabletsMutatorImpl(ServerContext context) {
     this(context, DataLevel::metaTable);
   }
@@ -95,8 +110,14 @@ public class ConditionalTabletsMutatorImpl implements Ample.ConditionalTabletsMu

     Preconditions.checkState(extents.putIfAbsent(extent.toMetaRow(), extent) == null,
         "Duplicate extents not handled %s", extent);
-    return new ConditionalTabletMutatorImpl(context, extent, mutations::add, rejectedHandlers::put,
-        operationDescriptions::put);
+    return new ConditionalTabletMutatorImpl(context, extent, mutations::add, (ke, rh) -> {
+      rejectedHandlers.put(ke, rh);
+      // keep a copy that survives reset, in case result mapping is evaluated lazily after process()
+      originalRejectedHandlers.put(ke, rh);
+    }, (ke, desc) -> {
+      operationDescriptions.put(ke, desc);
+      originalOperationDescriptions.put(ke, desc);
+    });
   }

   protected ConditionalWriter createConditionalWriter(Ample.DataLevel dataLevel)
@@ -254,9 +275,9 @@ public class ConditionalTabletsMutatorImpl implements Ample.ConditionalTabletsMu
           @Override
           public Status getStatus() {
             var status = _getStatus();
-            if (status == Status.REJECTED && rejectedHandlers.containsKey(extent)) {
+            if (status == Status.REJECTED && originalRejectedHandlers.containsKey(extent)) {
               var tabletMetadata = readMetadata();
-              var handler = rejectedHandlers.get(extent);
+              var handler = originalRejectedHandlers.get(extent);
               if (tabletMetadata == null && handler.callWhenTabletDoesNotExists()
                   && handler.test(null)) {
                 status = Status.ACCEPTED;
@@ -265,7 +286,7 @@ public class ConditionalTabletsMutatorImpl implements Ample.ConditionalTabletsMu
                 status = Status.ACCEPTED;
               }

-              Supplier<String> descSupplier = operationDescriptions.get(extent);
+              Supplier<String> descSupplier = originalOperationDescriptions.get(extent);
               String desc = (descSupplier == null) ? null : descSupplier.get();

               if (log.isTraceEnabled()) {
@@ -300,16 +321,15 @@ public class ConditionalTabletsMutatorImpl implements Ample.ConditionalTabletsMu
       } catch (TableNotFoundException e) {
         throw new RuntimeException(e);
       } finally {
-        // render inoperable because reuse is not tested
+        // reset to allow reuse with new set of mutations
         extents.clear();
         mutations.clear();
-        active = false;
+        rejectedHandlers.clear();
+        operationDescriptions.clear();
+        dataLevel = null;
       }
     } else {
-      // render inoperable because reuse is not tested
-      extents.clear();
-      mutations.clear();
-      active = false;
+      // no mutations were submitted
       return Map.of();
     }
   }
@@ -335,9 +355,6 @@ public class ConditionalTabletsMutatorImpl implements Ample.ConditionalTabletsMu
     }
   }

-  @Override
-  public void close() {}
-
   protected Function<DataLevel,String> getTableMapper() {
     return tableMapper;
   }
diff --git a/server/base/src/main/java/org/apache/accumulo/server/metadata/ServerAmpleImpl.java b/server/base/src/main/java/org/apache/accumulo/server/metadata/ServerAmpleImpl.java
