     this.context = context;
     this.scanServerRefStore =
         new ScanServerRefStoreImpl(context, SystemTables.SCAN_REF.tableName());
+    this.sharedConditionalTabletsMutator = new ConditionalTabletsMutatorImpl(context, tableMapper);
   }

   @Override
@@ -90,9 +91,11 @@ public class ServerAmpleImpl extends AmpleImpl implements Ample {
     return new TabletsMutatorImpl(context, getTableMapper());
   }

+  private final ConditionalTabletsMutatorImpl sharedConditionalTabletsMutator;
+
   @Override
   public ConditionalTabletsMutator conditionallyMutateTablets() {
-    return new ConditionalTabletsMutatorImpl(context, getTableMapper());
+    return sharedConditionalTabletsMutator;
   }

