    56→public class ConditionalTabletsMutatorImpl implements Ample.ConditionalTabletsMutator {
    57→
    58→  private static final Logger log = LoggerFactory.getLogger(ConditionalTabletsMutatorImpl.class);
    59→
    60→  private final ServerContext context;
    61→  private Ample.DataLevel dataLevel = null;
    62→
    63→  private final List<ConditionalMutation> mutations = new ArrayList<>();
    64→
    65→  private final Map<Text,KeyExtent> extents = new HashMap<>();
    66→
    67→  private boolean active = true;
    68→
    69→  final Map<KeyExtent,Ample.RejectionHandler> rejectedHandlers = new HashMap<>();
    70→  private final Map<KeyExtent,Supplier<String>> operationDescriptions = new HashMap<>();
    71→  private final Function<DataLevel,String> tableMapper;
    72→
    73→  public ConditionalTabletsMutatorImpl(ServerContext context) {
    74→    this(context, DataLevel::metaTable);
    75→  }
