    77→  public ConditionalTabletsMutatorImpl(ServerContext context,
    78→      Function<DataLevel,String> tableMapper) {
    79→    this.context = context;
    80→    this.tableMapper = Objects.requireNonNull(tableMapper);
    81→  }
    82→
    83→  @Override
    84→  public Ample.OperationRequirements mutateTablet(KeyExtent extent) {
    85→    Preconditions.checkState(active);
    86→
    87→    var dataLevel = Ample.DataLevel.of(extent.tableId());
    88→
    89→    if (this.dataLevel == null) {
    90→      this.dataLevel = dataLevel;
    91→    } else if (!this.dataLevel.equals(dataLevel)) {
    92→      throw new IllegalArgumentException(
    93→          "Can not mix data levels " + this.dataLevel + " " + dataLevel);
    94→    }
    95→
    96→    Preconditions.checkState(extents.putIfAbsent(extent.toMetaRow(), extent) == null,
    97→        "Duplicate extents not handled %s", extent);
    98→    return new ConditionalTabletMutatorImpl(context, extent, mutations::add, rejectedHandlers::put,
    99→        operationDescriptions::put);
   100→  }
   101→
   102→  protected ConditionalWriter createConditionalWriter(Ample.DataLevel dataLevel)
   103→      throws TableNotFoundException {
   104→    if (dataLevel == Ample.DataLevel.ROOT) {
   105→      return new RootConditionalWriter(context);
   106→    } else {
   107→      return context.createConditionalWriter(getTableMapper().apply(dataLevel));
   108→    }
   109→  }
   110→
   111→  protected Map<KeyExtent,TabletMetadata> readTablets(List<KeyExtent> extents) {
   112→    Map<KeyExtent,TabletMetadata> failedTablets = new HashMap<>();
   113→
   114→    try (var tabletsMeta = context.getAmple().readTablets().forTablets(extents, Optional.empty())
   115→        .saveKeyValues().build()) {
   116→      tabletsMeta
   117→          .forEach(tabletMetadata -> failedTablets.put(tabletMetadata.getExtent(), tabletMetadata));
   118→    }
   119→
   120→    return failedTablets;
   121→  }
   122→
