    81→public class ConditionalTabletMutatorImpl extends TabletMutatorBase<Ample.ConditionalTabletMutator>
    82→    implements Ample.ConditionalTabletMutator, Ample.OperationRequirements {
    83→
    84→  public static final int INITIAL_ITERATOR_PRIO = 1000000;
    85→
    86→  private final ConditionalMutation mutation;
    87→  private final Consumer<ConditionalMutation> mutationConsumer;
    88→
    89→  private final BiConsumer<KeyExtent,Ample.RejectionHandler> rejectionHandlerConsumer;
    90→
    91→  private final ServerContext context;
    92→  private final ServiceLock lock;
    93→  private final KeyExtent extent;
    94→  private final BiConsumer<KeyExtent,Supplier<String>> descriptionConsumer;
    95→
    96→  private boolean sawOperationRequirement = false;
    97→  private boolean checkPrevEndRow = true;
    98→
    99→  protected ConditionalTabletMutatorImpl(ServerContext context, KeyExtent extent,
   100→      Consumer<ConditionalMutation> mutationConsumer,
   101→      BiConsumer<KeyExtent,Ample.RejectionHandler> rejectionHandlerConsumer,
   102→      BiConsumer<KeyExtent,Supplier<String>> descriptionConsumer) {
   103→    super(new ConditionalMutation(extent.toMetaRow()));
   104→    this.mutation = (ConditionalMutation) super.mutation;
   105→    this.mutationConsumer = mutationConsumer;
   106→    this.rejectionHandlerConsumer = rejectionHandlerConsumer;
   107→    this.descriptionConsumer = descriptionConsumer;
   108→    this.extent = extent;
   109→    this.context = context;
   110→    this.lock = this.context.getServiceLock();
   111→    Objects.requireNonNull(this.lock, "ServiceLock not set on ServerContext");
   112→  }
   113→
   114→  @Override
   115→  public Ample.ConditionalTabletMutator requireAbsentLocation() {
   116→    Preconditions.checkState(updatesEnabled, "Cannot make updates after calling mutate.");
   117→
   118→    // It is not expected the encoder will actually be called, so throw an exception if it is.
   119→    Function<Location,byte[]> encoder = l -> {
   120→      throw new UnsupportedOperationException();
   121→    };
   122→
   123→    // The column families for each location type should conceptually be an empty set, so create
   124→    // conditions that check for this.
   125→    var condition1 = SetEncodingIterator.createCondition(Set.of(), encoder,
   126→        getLocationFamilyText(LocationType.FUTURE));
   127→    var condition2 = SetEncodingIterator.createCondition(Set.of(), encoder,
   128→        getLocationFamilyText(LocationType.CURRENT));
   129→
   130→    // Add the conditions for both location column families, both conditions must be met for the
   131→    // mutation to be applied.
   132→    mutation.addCondition(condition1);
   133→    mutation.addCondition(condition2);
   134→
   135→    return this;
   136→  }
   137→
   138→  @Override
   139→  public Ample.ConditionalTabletMutator requireLocation(Location location) {
   140→    Preconditions.checkState(updatesEnabled, "Cannot make updates after calling mutate.");
   141→    Preconditions.checkArgument(
   142→        location.getType() == LocationType.FUTURE || location.getType() == LocationType.CURRENT);
   143→    sawOperationRequirement = true;
   144→
   145→    Function<Location,Pair<byte[],byte[]>> encoder =
   146→        l -> new Pair<>(location.getSession().getBytes(UTF_8),
   147→            location.getHostPort().getBytes(UTF_8));
   148→
   149→    // The location column family can have multiple column qualifiers set. When requiring a location
   150→    // we want to check the location is set AND that no other location qualifiers are set on the
   151→    // column family. So the condition should conceptually check that the column family is a map of
   152→    // size one with only our expected location set in the map.
   153→    var condition1 = SetEncodingIterator.createConditionWithVal(Set.of(location), encoder,
   154→        getLocationFamilyText(location.getType()));
   155→
   156→    // Conceptually the column family for the other location type should be an empty map, so create
   157→    // a condition that checks this.
   158→    var otherLocType =
   159→        location.getType() == LocationType.CURRENT ? LocationType.FUTURE : LocationType.CURRENT;
   160→    var condition2 = SetEncodingIterator.createConditionWithVal(Set.of(), encoder,
   161→        getLocationFamilyText(otherLocType));
   162→
   163→    // Add the conditions for both location column families, both conditions must be met for the
   164→    // mutation to be applied.
   165→    mutation.addCondition(condition1);
   166→    mutation.addCondition(condition2);
   167→
   168→    return this;
   169→  }
   170→
   171→  @Override
   172→  public Ample.ConditionalTabletMutator requireCurrentLocationNotEqualTo(TServerInstance tsi) {
   173→    Preconditions.checkState(updatesEnabled, "Cannot make updates after calling mutate.");
   174→    Condition c = CurrentLocationNotEqualToIterator.createCondition(tsi);
   175→    mutation.addCondition(c);
   176→    return this;
   177→  }
   178→
   179→  @Override
   180→  public Ample.ConditionalTabletMutator
   181→      requireTabletAvailability(TabletAvailability tabletAvailability) {
   182→    Preconditions.checkState(updatesEnabled, "Cannot make updates after calling mutate.");
   183→    Condition c = new Condition(AVAILABILITY_COLUMN.getColumnFamily(),
   184→        AVAILABILITY_COLUMN.getColumnQualifier())
   185→        .setValue(TabletAvailabilityUtil.toValue(tabletAvailability).get());
   186→    mutation.addCondition(c);
   187→    return this;
   188→  }
