   190→  @Override
   191→  public Ample.ConditionalTabletMutator requireCompaction(ExternalCompactionId ecid) {
   192→    Preconditions.checkState(updatesEnabled, "Cannot make updates after calling mutate.");
   193→    IteratorSetting is = new IteratorSetting(INITIAL_ITERATOR_PRIO, PresentIterator.class);
   194→    Condition c = new Condition(ExternalCompactionColumnFamily.STR_NAME, ecid.canonical())
   195→        .setValue(PresentIterator.VALUE).setIterators(is);
   196→    mutation.addCondition(c);
   197→    return this;
   198→  }
