   203→    IteratorSetting is = new IteratorSetting(INITIAL_ITERATOR_PRIO, TabletExistsIterator.class);
   204→    Condition c = new Condition("", "").setIterators(is);
   205→    mutation.addCondition(c);
   206→    sawOperationRequirement = true;
   207→    checkPrevEndRow = false;
   208→    return this;
   209→  }
