   221→  public Ample.ConditionalTabletMutator requireOperation(TabletOperationId opid) {
   222→    Preconditions.checkState(updatesEnabled, "Cannot make updates after calling mutate.");
   223→    Condition c = new Condition(OPID_COLUMN.getColumnFamily(), OPID_COLUMN.getColumnQualifier())
   224→        .setValue(opid.canonical());
   225→    mutation.addCondition(c);
   226→    sawOperationRequirement = true;
   227→    return this;
   228→  }
   229→
   230→  private void requireSameSingle(TabletMetadata tabletMetadata, ColumnType type) {
   231→    switch (type) {
   232→      case PREV_ROW:
   233→        throw new IllegalStateException("PREV_ROW already set from Extent");
   234→      case LOGS: {
   235→        Condition c = SetEncodingIterator.createCondition(new HashSet<>(tabletMetadata.getLogs()),
   236→            logEntry -> logEntry.getColumnQualifier().toString().getBytes(UTF_8),
   237→            LogColumnFamily.NAME);
   238→        mutation.addCondition(c);
   239→      }
   240→        break;
   241→      case FILES: {
   242→        Condition c =
   243→            SetEncodingIterator.createConditionWithVal(tabletMetadata.getFilesMap().entrySet(),
   244→                entry -> new Pair<>(entry.getKey().getMetadata().getBytes(UTF_8),
   245→                    entry.getValue().encode()),
   246→                DataFileColumnFamily.NAME);
   247→        mutation.addCondition(c);
   248→      }
   249→        break;
   250→      case SELECTED: {
   251→        Condition c =
   252→            new Condition(SELECTED_COLUMN.getColumnFamily(), SELECTED_COLUMN.getColumnQualifier());
   253→        if (tabletMetadata.getSelectedFiles() != null) {
   254→          // ensure the SelectedFiles metadata value is re-encoded in case it was manually edited
   255→          c.setIterators(new IteratorSetting(INITIAL_ITERATOR_PRIO, SortedFilesIterator.class));
   256→          c = c.setValue(
   257→              Objects.requireNonNull(tabletMetadata.getSelectedFiles().getMetadataValue()));
   258→        }
   259→        mutation.addCondition(c);
   260→      }
   261→        break;
   262→      case ECOMP: {
   263→        Condition c =
   264→            SetEncodingIterator.createCondition(tabletMetadata.getExternalCompactions().keySet(),
   265→                ecid -> ecid.canonical().getBytes(UTF_8), ExternalCompactionColumnFamily.NAME);
   266→        mutation.addCondition(c);
   267→      }
   268→        break;
   269→      case LOCATION:
   270→        if (tabletMetadata.getLocation() == null) {
   271→          requireAbsentLocation();
   272→        } else {
   273→          requireLocation(tabletMetadata.getLocation());
   274→        }
   275→        break;
   276→      case LOADED: {
   277→        Condition c = SetEncodingIterator.createCondition(tabletMetadata.getLoaded().keySet(),
   278→            stf -> stf.getMetadata().getBytes(UTF_8), BulkFileColumnFamily.NAME);
   279→        mutation.addCondition(c);
   280→      }
   281→        break;
   282→      case COMPACTED: {
   283→        Condition c = SetEncodingIterator.createCondition(tabletMetadata.getCompacted(),
   284→            fTid -> fTid.canonical().getBytes(UTF_8), CompactedColumnFamily.NAME);
   285→        mutation.addCondition(c);
   286→      }
   287→        break;
   288→      case TIME: {
   289→        Condition c =
   290→            new Condition(TIME_COLUMN.getColumnFamily(), TIME_COLUMN.getColumnQualifier());
   291→        c = c.setValue(tabletMetadata.getTime().encode());
   292→        mutation.addCondition(c);
   293→      }
   294→        break;
   295→      case FLUSH_ID: {
   296→        Condition c =
   297→            new Condition(FLUSH_COLUMN.getColumnFamily(), FLUSH_COLUMN.getColumnQualifier());
   298→        if (tabletMetadata.getFlushId().isPresent()) {
   299→          c = c.setValue(Long.toString(tabletMetadata.getFlushId().getAsLong()));
   300→        }
   301→        mutation.addCondition(c);
   302→      }
   303→        break;
   304→      case USER_COMPACTION_REQUESTED: {
   305→        Condition c =
   306→            SetEncodingIterator.createCondition(tabletMetadata.getUserCompactionsRequested(),
   307→                fTid -> fTid.canonical().getBytes(UTF_8), UserCompactionRequestedColumnFamily.NAME);
   308→        mutation.addCondition(c);
   309→      }
   310→        break;
   311→      case SUSPEND: {
   312→        Condition c =
   313→            new Condition(SUSPEND_COLUMN.getColumnFamily(), SUSPEND_COLUMN.getColumnQualifier());
   314→        if (tabletMetadata.getSuspend() != null) {
   315→          c.setValue(tabletMetadata.getSuspend().toValue());
   316→        }
   317→        mutation.addCondition(c);
   318→      }
   319→        break;
   320→      case UNSPLITTABLE: {
   321→        Condition c = new Condition(UNSPLITTABLE_COLUMN.getColumnFamily(),
   322→            UNSPLITTABLE_COLUMN.getColumnQualifier());
   323→        if (tabletMetadata.getUnSplittable() != null) {
   324→          c.setValue(tabletMetadata.getUnSplittable().toBase64());
   325→        }
   326→        mutation.addCondition(c);
   327→      }
   328→        break;
   329→      default:
   330→        throw new UnsupportedOperationException("Column type " + type + " is not supported.");
   331→    }
   332→  }
   333→
   334→  @Override
   335→  public Ample.ConditionalTabletMutator requireSame(TabletMetadata tabletMetadata, ColumnType type,
   336→      ColumnType... otherTypes) {
   337→    Preconditions.checkState(updatesEnabled, "Cannot make updates after calling mutate.");
   338→    requireSameSingle(tabletMetadata, type);
   339→    for (var ct : otherTypes) {
   340→      requireSameSingle(tabletMetadata, ct);
   341→    }
   342→    return this;
   343→  }
   344→
   345→  @Override
   346→  public Ample.ConditionalTabletMutator requireAbsentLogs() {
   347→    Preconditions.checkState(updatesEnabled, "Cannot make updates after calling mutate.");
   348→    Condition c = SetEncodingIterator.createCondition(Set.<LogEntry>of(),
   349→        logEntry -> logEntry.getColumnQualifier().toString().getBytes(UTF_8), LogColumnFamily.NAME);
   350→    mutation.addCondition(c);
   351→    return this;
   352→  }
   353→
   354→  @Override
   355→  public ConditionalTabletMutator requireFiles(Set<StoredTabletFile> files) {
   356→    Preconditions.checkState(updatesEnabled, "Cannot make updates after calling mutate.");
   357→    IteratorSetting is = new IteratorSetting(INITIAL_ITERATOR_PRIO, PresentIterator.class);
   358→    for (StoredTabletFile file : files) {
   359→      Condition c = new Condition(DataFileColumnFamily.STR_NAME, file.getMetadata())
   360→          .setValue(PresentIterator.VALUE).setIterators(is);
   361→      mutation.addCondition(c);
   362→    }
   363→    return this;
   364→  }
   365→
   366→  @Override
   367→  public ConditionalTabletMutator requireLessOrEqualsFiles(long limit) {
   368→    Preconditions.checkState(updatesEnabled, "Cannot make updates after calling mutate.");
   369→    Condition c = ColumnFamilySizeLimitIterator.createCondition(DataFileColumnFamily.NAME, limit);
   370→    mutation.addCondition(c);
   371→    return this;
   372→  }
   373→
   374→  @Override
   375→  public ConditionalTabletMutator requireAbsentLoaded(Set<ReferencedTabletFile> files) {
   376→    Preconditions.checkState(updatesEnabled, "Cannot make updates after calling mutate.");
   377→    for (ReferencedTabletFile file : files) {
   378→      Condition c = new Condition(BulkFileColumnFamily.STR_NAME, file.insert().getMetadata());
   379→      mutation.addCondition(c);
   380→    }
   381→    return this;
   382→  }
   383→
   384→  @Override
   385→  public ConditionalTabletMutator requireCheckSuccess(TabletMetadataCheck check) {
   386→    Preconditions.checkState(updatesEnabled, "Cannot make updates after calling mutate.");
   387→    Condition condition = TabletMetadataCheckIterator.createCondition(check, extent);
   388→    mutation.addCondition(condition);
   389→    return this;
   390→  }
   391→
   392→  @Override
   393→  public ConditionalTabletMutator requireMigration(TServerInstance tserver) {
   394→    Preconditions.checkState(updatesEnabled, "Cannot make updates after calling mutate.");
   395→    Condition condition =
   396→        new Condition(MIGRATION_COLUMN.getColumnFamily(), MIGRATION_COLUMN.getColumnQualifier())
   397→            .setValue(tserver.getHostPortSession());
   398→    mutation.addCondition(condition);
   399→    return this;
   400→  }
   401→
   402→  @Override
   403→  public void submit(Ample.RejectionHandler rejectionCheck) {
   404→    Preconditions.checkState(updatesEnabled, "Cannot make updates after calling mutate.");
   405→    Preconditions.checkState(sawOperationRequirement, "No operation requirements were seen");
   406→    if (checkPrevEndRow) {
   407→      Condition c =
   408→          new Condition(PREV_ROW_COLUMN.getColumnFamily(), PREV_ROW_COLUMN.getColumnQualifier())
   409→              .setValue(encodePrevEndRow(extent.prevEndRow()).get());
   410→      mutation.addCondition(c);
   411→    }
   412→    if (putServerLock) {
   413→      this.putZooLock(lock);
   414→    }
   415→    getMutation();
   416→    mutationConsumer.accept(mutation);
   417→    rejectionHandlerConsumer.accept(extent, rejectionCheck);
   418→  }
   419→
   420→  @Override
   421→  public void submit(Ample.RejectionHandler rejectionHandler, Supplier<String> description) {
   422→    descriptionConsumer.accept(extent, description);
   423→    this.submit(rejectionHandler);
   424→  }
   425→}
